30 #ifndef FULLSCREENPHOTOVIEWER_H
31 #define FULLSCREENPHOTOVIEWER_H
32 
33 #include <QGraphicsScene>
34 #include <QGraphicsView>
35 #include <QKeyEvent>
36 #include <QMainWindow>
37 #include <QWheelEvent>
38 
54 class ZoomableGraphicsView : public QGraphicsView
55 {
56     Q_OBJECT
57 public:
67     explicit ZoomableGraphicsView(QWidget *parent = nullptr)
68         : QGraphicsView(parent)
69         , m_scaleFactor(1.0)
70     {
71         setTransformationAnchor(QGraphicsView::AnchorUnderMouse);
72         setDragMode(QGraphicsView::ScrollHandDrag);
73     }
74 
75 protected:
86     void wheelEvent(QWheelEvent *event) override
87     {
88         constexpr double zoomInFactor = 1.15;
89         constexpr double zoomOutFactor = 1.0 / zoomInFactor;
90 
91         if (event->angleDelta().y() > 0) {
92             scale(zoomInFactor, zoomInFactor);
93             m_scaleFactor *= zoomInFactor;
94         } else {
95             scale(zoomOutFactor, zoomOutFactor);
96             m_scaleFactor *= zoomOutFactor;
97         }
98         event->accept();
99     }
100 
101 private:
103     double m_scaleFactor;
104 };
105 
121 class FullScreenPhotoViewer : public QMainWindow
122 {
123     Q_OBJECT
124 public:
136     explicit FullScreenPhotoViewer(const QPixmap &pixmap, QWidget *parent = nullptr)
137         : QMainWindow(parent)
138     {
139         setWindowFlags(windowFlags() | Qt::FramelessWindowHint | Qt::WindowStaysOnTopHint);
140 
141         setWindowModality(Qt::ApplicationModal);
142         setAttribute(Qt::WA_DeleteOnClose, true);
143 
144         m_scene = new QGraphicsScene(this);
145         m_scene->addPixmap(pixmap);
146 
147         m_view = new ZoomableGraphicsView(this);
148         m_view->setScene(m_scene);
149 
150         setCentralWidget(m_view);
151 
152         activateWindow();
153         raise();
154         showFullScreen();
155     }
156 
157 protected:
166     void keyPressEvent(QKeyEvent *event) override
167     {
168         if (event->key() == Qt::Key_Escape) {
169             close();
170         } else {
171             QMainWindow::keyPressEvent(event);
172         }
173     }
174 
175 private:
177     QGraphicsScene *m_scene;
179     ZoomableGraphicsView *m_view;
180 };
181 
182 #endif // FULLSCREENPHOTOVIEWER_H
